import React from 'react';
import { FiPackage, FiTruck, FiBriefcase, FiMapPin, FiBox, FiGlobe } from 'react-icons/fi';

const ServiceCard = ({ icon: Icon, title, desc, color }) => (
  <div className="col-lg-3 col-md-4 col-sm-6 mb-4">
    <div className="card h-100 border-0 shadow-lg text-center p-4 rounded-4" 
         style={{ 
           transition: '0.3s', 
           cursor: 'pointer', 
           backgroundColor: 'rgba(255, 255, 255, 0.9)', 
           backdropFilter: 'blur(5px)',
           borderTop: `6px solid ${color}` 
         }}>
      <div className="mb-3 d-flex justify-content-center" style={{ fontSize: '2.5rem', color: color }}>
        <Icon />
      </div>
      <h6 className="fw-bold text-dark text-uppercase mb-2" style={{ fontSize: '0.9rem' }}>{title}</h6>
      <p className="text-muted mb-3" style={{ fontSize: '0.75rem' }}>{desc}</p>
      <button className="btn btn-sm rounded-pill px-4 mt-auto fw-bold" 
              style={{ backgroundColor: color, color: 'white', border: 'none' }}>Select</button>
    </div>
  </div>
);

const Home = () => {
  return (
    <div className="container py-5">
      <div className="text-center py-5">
        <h1 className="fw-bold text-dark mb-2" style={{ textShadow: '2px 2px 4px rgba(0,0,0,0.1)' }}>
          Logistics Aggregator Platform
        </h1>
        <h4 className="text-primary fw-bold bg-white d-inline-block px-4 py-2 rounded-pill shadow-sm">
          One Solution for All Deliveries
        </h4>
      </div>

      <div className="row g-4 justify-content-center pb-5">
        <ServiceCard icon={FiPackage} title="Courier Services" desc="Domestic & Express Delivery" color="#2ecc71" />
        <ServiceCard icon={FiTruck} title="Transport Services" desc="Roadways & Haulage Transport" color="#f1c40f" />
        <ServiceCard icon={FiBox} title="Packers & Movers" desc="Safe Home & Office Moving" color="#f39c12" />
        <ServiceCard icon={FiGlobe} title="International" desc="Air & Sea Freight Cargo" color="#9b59b6" />
        <ServiceCard icon={FiBriefcase} title="Business MSME" desc="Bulk, 3PL & Supply Chain" color="#3498db" />
        <ServiceCard icon={FiMapPin} title="Track & Trace" desc="Real-time Shipment Tracking" color="#e74c3c" />
      </div>
    </div>
  );
};

export default Home;
